/* ===========================================================================
 * DOCUMENT BATCH PLANNER  —  planDocumentBatches()
 * ---------------------------------------------------------------------------
 * STABLE INTERNAL CONTRACT. Lift-ready.
 *
 * This block is deliberately PURE and self-contained so it can be lifted VERBATIM
 * into a shared component (SW-016 Document Batch Planner) the moment a second
 * concrete consumer exists. It currently lives inside SW-008 because SW-008 is the
 * only consumer, and an Execute Workflow boundary for a pure function would buy a
 * real failure mode (item replacement / state loss — see Engineering Guidelines §3-4)
 * for no runtime benefit.
 *
 * INDEPENDENCE INVARIANTS (do not violate; they are what make it liftable):
 *   - Knows NOTHING about prompts (PR-001/PR-002), providers (OpenAI/Azure), or
 *     knowledge-unit semantics (statement/category/authoritySource).
 *   - Reads ONLY the normalized OCR model produced by SW-005.
 *   - No I/O, no side effects, no n8n globals ($json, $(), this.helpers).
 *   - Deterministic: identical input -> identical output.
 *
 * INPUT
 *   ocr     : normalized OCR model (SW-005). Uses ocr.paragraphs[] and ocr.pagination.
 *             paragraphs[] = [{ index, text, page, role, offset }]
 *   budget  : {
 *               maxPromptTokens      : number  // hard cap on OCR text tokens per batch
 *               overlapParagraphs    : number  // trailing paragraphs repeated into the next batch
 *               includeHeadingBreadcrumb : bool// prepend nearest heading ancestry as context
 *               maxBatches           : number  // runaway guard
 *               charsPerToken        : number  // estimation ratio (no tokenizer in the Code node)
 *             }
 *
 * OUTPUT
 *   {
 *     batches: [{
 *       index              : 1-based batch number
 *       paragraphs         : [{ index, text, page, role }]   // INCLUDING overlap paragraphs
 *       headingBreadcrumb  : string|null   // e.g. "3 Security > 3.2 Access Control"
 *       estimatedTokens    : number        // breadcrumb + locators + text
 *       firstParagraph     : number        // first paragraph.index in this batch (incl. overlap)
 *       lastParagraph      : number
 *       overlapFrom        : number|null   // paragraph.index where the overlap region starts
 *       newParagraphs      : number        // paragraphs NOT carried over as overlap
 *     }],
 *     stats: { totalBatches, totalParagraphs, totalEstimatedTokens,
 *              overlapParagraphsUsed, oversizedParagraphsSplit, truncated:false }
 *   }
 *
 * GUARANTEES
 *   - Every paragraph appears in at least one batch. NOTHING is dropped. There is no
 *     truncation: the planner's purpose is to make truncation unnecessary.
 *   - Paragraph boundaries are never split across batches, EXCEPT for a single paragraph
 *     that alone exceeds maxPromptTokens, which is split at sentence boundaries into parts
 *     that each retain the ORIGINAL paragraph.index and page (traceability preserved).
 *   - Batches are contiguous and ordered; overlap is a trailing window of the previous batch.
 * =========================================================================== */

function planDocumentBatches(ocr, budget) {
  const cfg = budget || {};
  const B = {
    maxPromptTokens:          Number(cfg.maxPromptTokens) || 19200,
    overlapParagraphs:        Number(cfg.overlapParagraphs != null ? cfg.overlapParagraphs : 3),
    includeHeadingBreadcrumb: cfg.includeHeadingBreadcrumb !== false,
    maxBatches:               Number(cfg.maxBatches) || 200,
    charsPerToken:            Number(cfg.charsPerToken) || 4,
  };

  const paragraphs = (ocr && Array.isArray(ocr.paragraphs)) ? ocr.paragraphs : [];
  const stats = {
    totalBatches: 0, totalParagraphs: paragraphs.length, totalEstimatedTokens: 0,
    overlapParagraphsUsed: 0, oversizedParagraphsSplit: 0, truncated: false,
  };
  if (!paragraphs.length) return { batches: [], stats };

  // ---- token estimation ---------------------------------------------------
  // No tokenizer is available in the n8n Code node, so we estimate from characters.
  // The caller absorbs the error via a safety margin applied to maxPromptTokens.
  const estTokens = (chars) => Math.ceil(chars / B.charsPerToken);
  const LOCATOR_CHARS = 18;              // "[p12:para143] (role) "
  const paraCost = (p) => estTokens(String(p.text || '').length + LOCATOR_CHARS);

  // ---- oversized-paragraph split ------------------------------------------
  // A single paragraph larger than the whole budget cannot fit any batch. Split it at
  // sentence boundaries. Each part KEEPS the original index and page, so
  // sourceParagraph / sourcePage traceability survives; `part` disambiguates.
  function splitOversized(p) {
    const maxChars = (B.maxPromptTokens - 200) * B.charsPerToken;   // room for framing
    const text = String(p.text || '');
    if (text.length <= maxChars) return [p];
    const sentences = text.split(/(?<=[.!?])\s+/);
    const parts = [];
    let cur = '';
    for (const s of sentences) {
      if (cur.length + s.length + 1 > maxChars && cur) { parts.push(cur); cur = s; }
      else { cur = cur ? cur + ' ' + s : s; }
    }
    if (cur) parts.push(cur);
    stats.oversizedParagraphsSplit++;
    return parts.map((t, i) => ({
      index: p.index,          // ORIGINAL index — traceability preserved
      page: p.page,            // ORIGINAL page
      role: p.role,
      text: t,
      part: i + 1,
      partsTotal: parts.length,
    }));
  }

  // Expand oversized paragraphs up front so packing sees only fittable units.
  // MUST precede breadcrumbFor(), which walks `units` — after expansion, positions in
  // `units` no longer correspond to positions in `paragraphs`.
  const units = [];
  for (const p of paragraphs) for (const u of splitOversized(p)) units.push(u);

  // ---- heading breadcrumb -------------------------------------------------
  // Structured REFERENCE context: the nearest heading ancestry above a batch start.
  // Lets a batch classify statements correctly when the owning section heading fell into
  // an earlier batch — a problem overlap structurally cannot solve (a heading may be
  // hundreds of paragraphs back). Rendered as reference context, NOT extractable content.
  function breadcrumbFor(unitPos) {
    if (!B.includeHeadingBreadcrumb) return null;
    let title = null, section = null;
    for (let i = Math.min(unitPos, units.length - 1); i >= 0; i--) {
      const u = units[i];
      if (!u) continue;
      if (u.role === 'sectionHeading' && !section) section = u.text;
      if (u.role === 'title' && !title) title = u.text;
      if (title && section) break;
    }
    const parts = [title, section].filter(Boolean);
    return parts.length ? parts.join(' > ') : null;
  }
  const breadcrumbCost = (bc) => (bc ? estTokens(bc.length + 40) : 0);   // + framing text

  // ---- greedy packing -----------------------------------------------------
  const batches = [];
  let i = 0;                       // position in units[]
  let carry = [];                  // overlap window carried from the previous batch

  while (i < units.length) {
    if (batches.length >= B.maxBatches) {
      // Runaway guard. Throw rather than silently drop content.
      throw new Error(
        'planDocumentBatches: exceeded maxBatches (' + B.maxBatches + ') at paragraph ' +
        units[i].index + '. Raise maxBatches or maxPromptTokens; content must not be dropped.'
      );
    }

    const bc = breadcrumbFor(i);
    let tokens = breadcrumbCost(bc);
    const batchParas = [];

    // Overlap first: trailing window of the previous batch, for boundary context.
    for (const c of carry) { batchParas.push(c); tokens += paraCost(c); }

    // Then pack new paragraphs until the budget is reached.
    let packedNew = 0;
    while (i < units.length) {
      const cost = paraCost(units[i]);
      if (tokens + cost > B.maxPromptTokens && packedNew > 0) break;   // full (never emit empty)
      batchParas.push(units[i]);
      tokens += cost;
      packedNew++;
      i++;
    }

    batches.push({
      index: batches.length + 1,
      paragraphs: batchParas,
      headingBreadcrumb: bc,
      estimatedTokens: tokens,
      firstParagraph: batchParas[0].index,
      lastParagraph: batchParas[batchParas.length - 1].index,
      overlapFrom: carry.length ? carry[0].index : null,
      newParagraphs: packedNew,
    });
    stats.totalEstimatedTokens += tokens;
    stats.overlapParagraphsUsed += carry.length;

    // Overlap window for the NEXT batch: last N of THIS batch's NEW paragraphs.
    // (Never re-overlap an overlap — that would compound across batches.)
    const newOnly = batchParas.slice(carry.length);
    carry = (B.overlapParagraphs > 0 && i < units.length)
      ? newOnly.slice(-B.overlapParagraphs)
      : [];
  }

  stats.totalBatches = batches.length;
  return { batches, stats };
}

/* ---------------------------------------------------------------------------
 * renderBatch() — turn a planned batch into prompt-ready text.
 * Kept separate from planning: the PLANNER decides *what* goes in a batch; the
 * RENDERER decides *how it is presented*. Only the renderer is opinionated about
 * locator syntax, and it is still prompt/provider agnostic.
 *
 * The heading breadcrumb is rendered as explicit REFERENCE CONTEXT and clearly
 * fenced off, so a consumer's prompt can instruct the model not to extract from it.
 * ------------------------------------------------------------------------- */
function renderBatch(batch) {
  const lines = [];

  if (batch.headingBreadcrumb) {
    lines.push('--- REFERENCE CONTEXT (for interpretation only; do NOT extract from this section) ---');
    lines.push('Current section: ' + batch.headingBreadcrumb);
    lines.push('--- END REFERENCE CONTEXT ---');
    lines.push('');
  }

  lines.push('--- DOCUMENT EXCERPT (extract from this section only) ---');
  let lastPage = null;
  for (const p of batch.paragraphs) {
    if (p.page != null && p.page !== lastPage) {
      lines.push('=== PAGE ' + p.page + ' ===');
      lastPage = p.page;
    }
    const loc = (p.page != null) ? ('p' + p.page + ':para' + p.index) : ('para' + p.index);
    // Only mark parts when a paragraph was ACTUALLY split (partsTotal > 1). Emitting
    // "part 1/1" on every unsplit paragraph is prompt noise and invites the model to
    // treat it as meaningful.
    const part = (p.partsTotal && p.partsTotal > 1) ? (' part ' + p.part + '/' + p.partsTotal) : '';
    const role = p.role ? (' (' + p.role + ')') : '';
    lines.push('[' + loc + part + ']' + role + ' ' + p.text);
  }
  lines.push('--- END DOCUMENT EXCERPT ---');
  return lines.join('\n');
}

// ===== SW-008 plan() — build the batch plan and seed loop state on the ITEM =====
const incoming = $('When Executed by WF-001').first().json;
const prow = $('Load PR-001 + LLM Settings').first().json;
const s = prow.settings || {};

// Token budget (R-08: authored config, never hardcoded).
const tpmBudget            = Number(s.tpmBudget ?? 30000);
const reservedOutputTokens = Number(s.reservedOutputTokens ?? 4000);
const safetyMargin         = Number(s.safetyMargin ?? 0.80);
const promptOverhead       = Number(s.promptOverheadTokens ?? 800);
const maxPromptTokens = Math.max(1000,
  Math.floor(tpmBudget * safetyMargin - reservedOutputTokens - promptOverhead));

const budget = {
  maxPromptTokens,
  overlapParagraphs:        Number(s.batchOverlapParagraphs ?? 3),
  includeHeadingBreadcrumb: s.includeHeadingBreadcrumb !== false,
  maxBatches:               Number(s.maxBatches ?? 60),
  charsPerToken:            Number(s.charsPerToken ?? 4),
};

const ocr = incoming.ocr || {};
const plan = planDocumentBatches(ocr, budget);

// paragraph roles -> needed by the merge ranking (rule 4: body text beats header/footer)
const paragraphRoles = {};
for (const p of (ocr.paragraphs || [])) if (p.role) paragraphRoles[p.index] = p.role;

// Pacing is NOT pre-computed here: collect() derives it from the ACTUAL tokens each batch
// spent (usage.total_tokens), which is both more accurate and self-correcting. We seed 0 so
// the first batch is issued immediately.
const pacingMs = 0;

console.log('[SW-008 plan] ' + JSON.stringify({
  paragraphs: plan.stats.totalParagraphs,
  batches: plan.stats.totalBatches,
  maxPromptTokens,
  estTotalTokens: plan.stats.totalEstimatedTokens,
  overlapParagraphs: budget.overlapParagraphs,
  oversizedSplit: plan.stats.oversizedParagraphsSplit,
}));

if (plan.stats.totalBatches === 0) {
  throw new Error('SW-008: OCR produced no paragraphs to extract from.');
}

return [{ json: { ...incoming,
  _bx: {
    batches: plan.batches,
    planStats: plan.stats,
    cursor: 0,                 // index of the NEXT batch to execute
    results: [],               // accumulated per-batch outputs — rides the ITEM (§3.6)
    rejected: [],              // hallucinated-locator rejections
    paragraphRoles,
    pacingMs,
    reservedOutputTokens,
  } }}];

// ===== SW-008 build-request() — render the CURRENT batch into a PR-001 chat request =====
// Reads the item on the wire (loop state rides the item — Guidelines §3.6). No history lookup.
const st = $json._bx;
const batch = st.batches[st.cursor];

const prow = $('Load PR-001 + LLM Settings').first().json;
const s = prow.settings || {};
const sys = prow.system_prompt || '';

// --- renderBatch(): planner's companion renderer (kept with the planner block in plan(),
// duplicated here verbatim so this node is self-contained; identical output).
function renderBatch(b) {
  const lines = [];
  if (b.headingBreadcrumb) {
    lines.push('--- REFERENCE CONTEXT (for interpretation only; do NOT extract from this section) ---');
    lines.push('Current section: ' + b.headingBreadcrumb);
    lines.push('--- END REFERENCE CONTEXT ---');
    lines.push('');
  }
  lines.push('--- DOCUMENT EXCERPT (extract from this section only) ---');
  let lastPage = null;
  for (const p of b.paragraphs) {
    if (p.page != null && p.page !== lastPage) { lines.push('=== PAGE ' + p.page + ' ==='); lastPage = p.page; }
    const loc = (p.page != null) ? ('p' + p.page + ':para' + p.index) : ('para' + p.index);
    const part = (p.partsTotal && p.partsTotal > 1) ? (' part ' + p.part + '/' + p.partsTotal) : '';
    const role = p.role ? (' (' + p.role + ')') : '';
    lines.push('[' + loc + part + ']' + role + ' ' + p.text);
  }
  lines.push('--- END DOCUMENT EXCERPT ---');
  return lines.join('\n');
}

const excerpt = renderBatch(batch);
// PR-001 is UNCHANGED. The {{ocr}} placeholder now receives one batch instead of the whole
// document — same contract, same locators, smaller window.
const usr = (prow.user_prompt || '').replace('{{ocr}}', excerpt);

console.log('[SW-008 batch ' + batch.index + '/' + st.batches.length + '] '
  + JSON.stringify({ paragraphs: batch.paragraphs.length, newParagraphs: batch.newParagraphs,
      range: batch.firstParagraph + '-' + batch.lastParagraph,
      estTokens: batch.estimatedTokens, promptChars: usr.length,
      breadcrumb: batch.headingBreadcrumb }));

// NOTE: the OpenAI (HTTP Request) node REPLACES the item and DROPS everything here
// (Engineering Guidelines §3.5). collect() therefore restores _bx by NODE REFERENCE from
// THIS node — not from the item chain. _batchMarker lets collect() verify it restored the
// state for the batch it actually sent, rather than silently processing the wrong one.
return [{ json: { ...$json,
  _model: s.model,
  _temp:  s.temperature ?? 0,
  _max:   Number(st.reservedOutputTokens) || 4096,
  _batchMarker: batch.index,
  messages: [ ...(sys ? [{ role: 'system', content: sys }] : []), { role: 'user', content: usr } ]
}}];

/* ===========================================================================
 * BATCH MERGE — mergeKnowledgeUnits()
 * ---------------------------------------------------------------------------
 * SW-008-SPECIFIC. Unlike the planner, this IS coupled to knowledge-unit semantics
 * (statement / category / authoritySource / sourcePage / sourceParagraph), so it
 * deliberately stays inside SW-008 and is NOT a candidate for extraction.
 *
 * PROBLEM
 *   Batches overlap by N paragraphs, so the same statement is legitimately extracted
 *   more than once. Restated requirements (exec summary vs normative body) also produce
 *   lexical duplicates across distant batches.
 *
 * POLICY (Architecture Owner approved)
 *   De-duplicate on normalized statement text, and when duplicates exist select the
 *   occurrence with the strongest EVIDENCE QUALITY — not the first by document order.
 *   "First wins" is arbitrary: in a document with an executive summary, the first
 *   occurrence is often the LOOSEST paraphrase, while the precise normative statement
 *   appears later. Ranking by evidence quality selects the better instance.
 *
 * RANKING (in order; first discriminator wins)
 *   1. non-null authoritySource      — a unit that cites its authority is strictly
 *                                      more useful for compliance than one that does not
 *   2. specific category over 'Other'— 'Other' is the model's fallback
 *   3. non-null sourcePage           — matters for PDFs; for DOCX all pages are null,
 *                                      so this tie-breaks to nothing and falls through
 *   4. body text over header/footer  — a requirement restated in a running header is
 *                                      not the authoritative instance
 *   5. lowest sourceParagraph        — DETERMINISTIC final tie-break (reproducibility)
 *
 * CONFLICT LOGGING (observability only — no schema change, no review queue)
 *   When two occurrences of the same statement disagree on category or authoritySource,
 *   the conflict is recorded so the ranking's choices are auditable. This is a real
 *   information loss and should be visible, not silent.
 * =========================================================================== */

const CATEGORY_FALLBACK = 'Other';
const NON_BODY_ROLES = { pageHeader: 1, pageFooter: 1, footnote: 1 };

function normalizeStatement(s) {
  return String(s || '').trim().toLowerCase().replace(/\s+/g, ' ');
}

/**
 * Score a unit's evidence quality. Higher is better. Compared field-by-field in
 * priority order rather than as a single number, so the discriminators stay explicit
 * and auditable (a weighted sum would make "why did it pick this one" unanswerable).
 */
function qualityKey(ku, paragraphRoles) {
  const role = paragraphRoles ? paragraphRoles[ku.sourceParagraph] : null;
  return [
    ku.authoritySource ? 1 : 0,                                   // 1. cites authority
    (ku.category && ku.category !== CATEGORY_FALLBACK) ? 1 : 0,   // 2. specific category
    (ku.sourcePage != null) ? 1 : 0,                              // 3. has a page
    (role && NON_BODY_ROLES[role]) ? 0 : 1,                       // 4. body text
  ];
}

/** Lexicographic compare of quality keys. Returns >0 if a is better than b. */
function compareQuality(a, b) {
  for (let i = 0; i < a.length; i++) {
    if (a[i] !== b[i]) return a[i] - b[i];
  }
  return 0;
}

/**
 * @param batchResults [{ batchIndex, knowledgeUnits: [...] }]
 * @param paragraphRoles { [paragraphIndex]: role }  — from ocr.paragraphs, for rule 4
 * @returns { knowledgeUnits, conflicts, stats }
 */
function mergeKnowledgeUnits(batchResults, paragraphRoles) {
  const byStatement = new Map();     // normalized statement -> { ku, batchIndex, key }
  const conflicts = [];
  const stats = {
    totalExtracted: 0,
    unique: 0,
    duplicatesDropped: 0,
    conflictsDetected: 0,
    replacedByBetterEvidence: 0,
  };

  for (const batch of (batchResults || [])) {
    for (const ku of (batch.knowledgeUnits || [])) {
      const statement = String(ku.statement || '').trim();
      if (!statement) continue;                 // SW-011 would reject it anyway
      stats.totalExtracted++;

      const key = normalizeStatement(statement);
      const incomingQ = qualityKey(ku, paragraphRoles);
      const existing = byStatement.get(key);

      if (!existing) {
        byStatement.set(key, { ku, batchIndex: batch.batchIndex, quality: incomingQ });
        continue;
      }

      // --- duplicate found ---
      stats.duplicatesDropped++;

      // Record disagreement BEFORE choosing, so the log reflects what was actually in conflict.
      const catDiff  = (existing.ku.category || null) !== (ku.category || null);
      const authDiff = (existing.ku.authoritySource || null) !== (ku.authoritySource || null);
      if (catDiff || authDiff) {
        stats.conflictsDetected++;
        conflicts.push({
          statement: statement.slice(0, 160),
          occurrences: [
            { batchIndex: existing.batchIndex, category: existing.ku.category || null,
              authoritySource: existing.ku.authoritySource || null,
              sourceParagraph: existing.ku.sourceParagraph ?? null },
            { batchIndex: batch.batchIndex, category: ku.category || null,
              authoritySource: ku.authoritySource || null,
              sourceParagraph: ku.sourceParagraph ?? null },
          ],
          conflictOn: [catDiff ? 'category' : null, authDiff ? 'authoritySource' : null].filter(Boolean),
        });
      }

      const cmp = compareQuality(incomingQ, existing.quality);
      let takeIncoming;
      if (cmp > 0) {
        takeIncoming = true;                    // strictly better evidence
      } else if (cmp < 0) {
        takeIncoming = false;
      } else {
        // 5. deterministic final tie-break: lowest sourceParagraph.
        const a = ku.sourceParagraph ?? Number.MAX_SAFE_INTEGER;
        const b = existing.ku.sourceParagraph ?? Number.MAX_SAFE_INTEGER;
        takeIncoming = a < b;
      }

      if (takeIncoming) {
        if (cmp > 0) stats.replacedByBetterEvidence++;
        byStatement.set(key, { ku, batchIndex: batch.batchIndex, quality: incomingQ });
      }
    }
  }

  // Emit in document order (by sourceParagraph) — stable, readable, and matches the
  // order a reviewer would expect when auditing the repository.
  const knowledgeUnits = Array.from(byStatement.values())
    .map((e) => e.ku)
    .sort((a, b) => (a.sourceParagraph ?? 0) - (b.sourceParagraph ?? 0));

  stats.unique = knowledgeUnits.length;
  // Record the conflict count for the merge decision, then attach conflicts for logging.
  return { knowledgeUnits, conflicts, stats };
}

/* ===========================================================================
 * BATCH RESULT VALIDATION — validateBatchUnits()
 * ---------------------------------------------------------------------------
 * Rejects hallucinated locators. A knowledge unit whose sourceParagraph does not
 * exist in the batch it came from was not grounded in the text we sent — it is a
 * fabrication, and admitting it would silently corrupt evidence traceability.
 *
 * This check does not exist in the single-call design and is a strict improvement:
 * batching makes the grounding set small and explicit, so we can actually verify it.
 * =========================================================================== */
function validateBatchUnits(units, batch) {
  const allowed = new Set(batch.paragraphs.map((p) => p.index));
  const accepted = [];
  const rejected = [];

  for (const ku of (units || [])) {
    const stmt = String(ku.statement || '').trim();
    if (!stmt) { rejected.push({ ku, reason: 'empty statement' }); continue; }

    const sp = ku.sourceParagraph;
    if (sp == null) {
      // PR-001 asks for a locator. A missing one is not fatal (SW-011 tolerates null),
      // but it is worth surfacing — it means the unit cannot be traced to a paragraph.
      accepted.push({ ...ku, _locatorMissing: true });
      continue;
    }
    if (!allowed.has(Number(sp))) {
      rejected.push({
        ku,
        reason: 'hallucinated locator: sourceParagraph ' + sp +
                ' is not in batch ' + batch.index +
                ' (paragraphs ' + batch.firstParagraph + '-' + batch.lastParagraph + ')',
      });
      continue;
    }
    accepted.push(ku);
  }
  return { accepted, rejected };
}

// ===== SW-008 collect() — validate this batch, ACCUMULATE onto the item, advance =====
//
// STATE RESTORATION (Engineering Guidelines §3.5).
// The OpenAI node is an HTTP Request node: it REPLACES the item and drops everything we put
// on it. The item arriving here is ONLY the API response ({ id, choices, usage, ... }) —
// $json._bx does NOT exist. So we restore loop state by NODE REFERENCE from build-request(),
// the last node before the HTTP call that carried it.
//
// This reads the CURRENT run of an upstream node, which is reliable (SW-005's poll-eval does
// exactly this across its own HTTP node). It is NOT the same as reconstructing EARLIER runs
// of a loop node, which §3.6 establishes as unreliable on n8n 2.29.9. Current run: fine.
// Past runs: not available. collect() only needs the current one.
const req = $('build-request() — Render Batch').first().json;
if (!req || !req._bx) {
  throw new Error('SW-008 collect(): could not restore loop state from build-request(). '
    + 'The HTTP node drops the item (§3.5) and the node reference did not resolve.');
}
const st = { ...req._bx };
const batch = st.batches[st.cursor];
if (!batch) {
  throw new Error('SW-008 collect(): restored cursor ' + st.cursor
    + ' has no batch (total ' + st.batches.length + ').');
}
// Verify we restored the state for the batch that was ACTUALLY sent. If the node reference
// ever resolved to a different iteration, fail loudly rather than attribute this response to
// the wrong batch (which would corrupt locator validation and the merge).
if (req._batchMarker != null && Number(req._batchMarker) !== Number(batch.index)) {
  throw new Error('SW-008 collect(): state/response mismatch — restored batch '
    + batch.index + ' but the request was for batch ' + req._batchMarker + '.');
}

const res  = $json;                      // the API response (item was replaced)
const body = res.body || res;            // fullResponse -> .body; otherwise the item IS the body
const httpStatus = res.statusCode;

// --- 429 / transient: back off and RETRY THIS BATCH (do not advance the cursor).
if (httpStatus === 429 || (httpStatus >= 500 && httpStatus < 600)) {
  const attempts = Number(st.retryAttempts || 0) + 1;
  if (attempts > 5) {
    throw new Error('SW-008: batch ' + batch.index + ' failed after 5 retries (HTTP ' + httpStatus + ').');
  }
  const backoffMs = Math.min(60000, 2000 * Math.pow(2, attempts - 1));
  console.log('[SW-008 batch ' + batch.index + '] HTTP ' + httpStatus
    + ' -> retry ' + attempts + '/5 after ' + backoffMs + 'ms');
  // Rebuild the item from the trigger + restored state (the HTTP node dropped both).
  const incomingR = $('When Executed by WF-001').first().json;
  return [{ json: { ...incomingR,
    _bx: { ...st, retryAttempts: attempts, pacingMs: backoffMs } } }];
}
if (httpStatus && httpStatus >= 400) {
  throw new Error('SW-008: batch ' + batch.index + ' HTTP ' + httpStatus + ': '
    + JSON.stringify(body).slice(0, 300));
}

// --- parse the model's JSON output
const content = (((body.choices || [])[0] || {}).message || {}).content || '';
let parsed;
try {
  parsed = JSON.parse(String(content).replace(/^```(?:json)?|```$/gm, '').trim());
} catch (e) {
  throw new Error('SW-008: batch ' + batch.index + ' returned unparseable JSON: '
    + String(content).slice(0, 200));
}
const rawUnits = Array.isArray(parsed) ? parsed : (parsed.knowledgeUnits || []);

// --- reject hallucinated locators (units citing paragraphs not in THIS batch)
const v = validateBatchUnits(rawUnits, batch);
if (v.rejected.length) {
  console.log('[SW-008 batch ' + batch.index + '] rejected ' + v.rejected.length
    + ' unit(s) with ungrounded locators: '
    + JSON.stringify(v.rejected.slice(0, 3).map(r => r.reason)));
}
console.log('[SW-008 batch ' + batch.index + '/' + st.batches.length + '] extracted '
  + v.accepted.length + ' unit(s), rejected ' + v.rejected.length
  + ' | tokens used: ' + JSON.stringify((body.usage || {})));

// --- ACCUMULATE on the item and advance the cursor
st.results  = [...st.results, { batchIndex: batch.index, knowledgeUnits: v.accepted }];
st.rejected = [...st.rejected, ...v.rejected.map(r => ({ batchIndex: batch.index, reason: r.reason }))];
st.cursor   = st.cursor + 1;
st.retryAttempts = 0;

// --- PACING, computed from ACTUAL token spend (not an a-priori estimate) ---
// Constraint: keep the rolling 60s token spend under tpmBudget.
// After spending `used` tokens, we must wait  used / (tpmBudget/60s)  before the next call.
// HARD CAP at 55s: an n8n Wait over ~65s is offloaded to the DB, which is unsupported under
// Queue Mode + filesystem binary storage. Capping keeps the sleep in-memory.
// Skip the wait entirely after the FINAL batch — nothing follows it.
const prow = $('Load PR-001 + LLM Settings').first().json;
const s = prow.settings || {};
const tpmBudget = Number(s.tpmBudget ?? 30000);
const WAIT_CAP_MS = Number(s.maxPacingMs ?? 55000);

const usage = body.usage || {};
const used = Number(usage.total_tokens
  || ((usage.prompt_tokens || 0) + (usage.completion_tokens || 0))
  || (batch.estimatedTokens + Number(st.reservedOutputTokens || 0)));   // fallback: our estimate

const isLastBatch = st.cursor >= st.batches.length;
let pacingMs;
if (isLastBatch) {
  pacingMs = 0;
} else if (s.batchPacingMs != null) {
  pacingMs = Number(s.batchPacingMs);                    // explicit override wins
} else {
  pacingMs = Math.ceil((used / tpmBudget) * 60000);      // proportional to what we actually spent
}
pacingMs = Math.min(pacingMs, WAIT_CAP_MS);
st.pacingMs = Math.max(0, pacingMs);

if (!isLastBatch) {
  console.log('[SW-008 batch ' + batch.index + '] tokens used=' + used
    + ' -> pacing ' + st.pacingMs + 'ms (cap ' + WAIT_CAP_MS + 'ms)');
}

// Rebuild the item for the next loop pass. $json here is the API RESPONSE, not our item —
// so we reconstruct from the trigger payload plus the restored/advanced state. This also
// means no request scaffolding (messages/_model/_max) or HTTP fields ride the loop.
const incoming = $('When Executed by WF-001').first().json;
return [{ json: { ...incoming, _bx: st } }];

/* ===========================================================================
 * BATCH MERGE — mergeKnowledgeUnits()
 * ---------------------------------------------------------------------------
 * SW-008-SPECIFIC. Unlike the planner, this IS coupled to knowledge-unit semantics
 * (statement / category / authoritySource / sourcePage / sourceParagraph), so it
 * deliberately stays inside SW-008 and is NOT a candidate for extraction.
 *
 * PROBLEM
 *   Batches overlap by N paragraphs, so the same statement is legitimately extracted
 *   more than once. Restated requirements (exec summary vs normative body) also produce
 *   lexical duplicates across distant batches.
 *
 * POLICY (Architecture Owner approved)
 *   De-duplicate on normalized statement text, and when duplicates exist select the
 *   occurrence with the strongest EVIDENCE QUALITY — not the first by document order.
 *   "First wins" is arbitrary: in a document with an executive summary, the first
 *   occurrence is often the LOOSEST paraphrase, while the precise normative statement
 *   appears later. Ranking by evidence quality selects the better instance.
 *
 * RANKING (in order; first discriminator wins)
 *   1. non-null authoritySource      — a unit that cites its authority is strictly
 *                                      more useful for compliance than one that does not
 *   2. specific category over 'Other'— 'Other' is the model's fallback
 *   3. non-null sourcePage           — matters for PDFs; for DOCX all pages are null,
 *                                      so this tie-breaks to nothing and falls through
 *   4. body text over header/footer  — a requirement restated in a running header is
 *                                      not the authoritative instance
 *   5. lowest sourceParagraph        — DETERMINISTIC final tie-break (reproducibility)
 *
 * CONFLICT LOGGING (observability only — no schema change, no review queue)
 *   When two occurrences of the same statement disagree on category or authoritySource,
 *   the conflict is recorded so the ranking's choices are auditable. This is a real
 *   information loss and should be visible, not silent.
 * =========================================================================== */

const CATEGORY_FALLBACK = 'Other';
const NON_BODY_ROLES = { pageHeader: 1, pageFooter: 1, footnote: 1 };

function normalizeStatement(s) {
  return String(s || '').trim().toLowerCase().replace(/\s+/g, ' ');
}

/**
 * Score a unit's evidence quality. Higher is better. Compared field-by-field in
 * priority order rather than as a single number, so the discriminators stay explicit
 * and auditable (a weighted sum would make "why did it pick this one" unanswerable).
 */
function qualityKey(ku, paragraphRoles) {
  const role = paragraphRoles ? paragraphRoles[ku.sourceParagraph] : null;
  return [
    ku.authoritySource ? 1 : 0,                                   // 1. cites authority
    (ku.category && ku.category !== CATEGORY_FALLBACK) ? 1 : 0,   // 2. specific category
    (ku.sourcePage != null) ? 1 : 0,                              // 3. has a page
    (role && NON_BODY_ROLES[role]) ? 0 : 1,                       // 4. body text
  ];
}

/** Lexicographic compare of quality keys. Returns >0 if a is better than b. */
function compareQuality(a, b) {
  for (let i = 0; i < a.length; i++) {
    if (a[i] !== b[i]) return a[i] - b[i];
  }
  return 0;
}

/**
 * @param batchResults [{ batchIndex, knowledgeUnits: [...] }]
 * @param paragraphRoles { [paragraphIndex]: role }  — from ocr.paragraphs, for rule 4
 * @returns { knowledgeUnits, conflicts, stats }
 */
function mergeKnowledgeUnits(batchResults, paragraphRoles) {
  const byStatement = new Map();     // normalized statement -> { ku, batchIndex, key }
  const conflicts = [];
  const stats = {
    totalExtracted: 0,
    unique: 0,
    duplicatesDropped: 0,
    conflictsDetected: 0,
    replacedByBetterEvidence: 0,
  };

  for (const batch of (batchResults || [])) {
    for (const ku of (batch.knowledgeUnits || [])) {
      const statement = String(ku.statement || '').trim();
      if (!statement) continue;                 // SW-011 would reject it anyway
      stats.totalExtracted++;

      const key = normalizeStatement(statement);
      const incomingQ = qualityKey(ku, paragraphRoles);
      const existing = byStatement.get(key);

      if (!existing) {
        byStatement.set(key, { ku, batchIndex: batch.batchIndex, quality: incomingQ });
        continue;
      }

      // --- duplicate found ---
      stats.duplicatesDropped++;

      // Record disagreement BEFORE choosing, so the log reflects what was actually in conflict.
      const catDiff  = (existing.ku.category || null) !== (ku.category || null);
      const authDiff = (existing.ku.authoritySource || null) !== (ku.authoritySource || null);
      if (catDiff || authDiff) {
        stats.conflictsDetected++;
        conflicts.push({
          statement: statement.slice(0, 160),
          occurrences: [
            { batchIndex: existing.batchIndex, category: existing.ku.category || null,
              authoritySource: existing.ku.authoritySource || null,
              sourceParagraph: existing.ku.sourceParagraph ?? null },
            { batchIndex: batch.batchIndex, category: ku.category || null,
              authoritySource: ku.authoritySource || null,
              sourceParagraph: ku.sourceParagraph ?? null },
          ],
          conflictOn: [catDiff ? 'category' : null, authDiff ? 'authoritySource' : null].filter(Boolean),
        });
      }

      const cmp = compareQuality(incomingQ, existing.quality);
      let takeIncoming;
      if (cmp > 0) {
        takeIncoming = true;                    // strictly better evidence
      } else if (cmp < 0) {
        takeIncoming = false;
      } else {
        // 5. deterministic final tie-break: lowest sourceParagraph.
        const a = ku.sourceParagraph ?? Number.MAX_SAFE_INTEGER;
        const b = existing.ku.sourceParagraph ?? Number.MAX_SAFE_INTEGER;
        takeIncoming = a < b;
      }

      if (takeIncoming) {
        if (cmp > 0) stats.replacedByBetterEvidence++;
        byStatement.set(key, { ku, batchIndex: batch.batchIndex, quality: incomingQ });
      }
    }
  }

  // Emit in document order (by sourceParagraph) — stable, readable, and matches the
  // order a reviewer would expect when auditing the repository.
  const knowledgeUnits = Array.from(byStatement.values())
    .map((e) => e.ku)
    .sort((a, b) => (a.sourceParagraph ?? 0) - (b.sourceParagraph ?? 0));

  stats.unique = knowledgeUnits.length;
  // Record the conflict count for the merge decision, then attach conflicts for logging.
  return { knowledgeUnits, conflicts, stats };
}

/* ===========================================================================
 * BATCH RESULT VALIDATION — validateBatchUnits()
 * ---------------------------------------------------------------------------
 * Rejects hallucinated locators. A knowledge unit whose sourceParagraph does not
 * exist in the batch it came from was not grounded in the text we sent — it is a
 * fabrication, and admitting it would silently corrupt evidence traceability.
 *
 * This check does not exist in the single-call design and is a strict improvement:
 * batching makes the grounding set small and explicit, so we can actually verify it.
 * =========================================================================== */
function validateBatchUnits(units, batch) {
  const allowed = new Set(batch.paragraphs.map((p) => p.index));
  const accepted = [];
  const rejected = [];

  for (const ku of (units || [])) {
    const stmt = String(ku.statement || '').trim();
    if (!stmt) { rejected.push({ ku, reason: 'empty statement' }); continue; }

    const sp = ku.sourceParagraph;
    if (sp == null) {
      // PR-001 asks for a locator. A missing one is not fatal (SW-011 tolerates null),
      // but it is worth surfacing — it means the unit cannot be traced to a paragraph.
      accepted.push({ ...ku, _locatorMissing: true });
      continue;
    }
    if (!allowed.has(Number(sp))) {
      rejected.push({
        ku,
        reason: 'hallucinated locator: sourceParagraph ' + sp +
                ' is not in batch ' + batch.index +
                ' (paragraphs ' + batch.firstParagraph + '-' + batch.lastParagraph + ')',
      });
      continue;
    }
    accepted.push(ku);
  }
  return { accepted, rejected };
}

// ===== SW-008 merge() — dedup + evidence-quality ranking + conflict logging =====
// The item arriving here ALREADY carries every batch result (accumulated by collect()).
// We do NOT reconstruct history from the OpenAI node's runs — that is unreliable (§3.6).
const incoming = $('When Executed by WF-001').first().json;
const st = $json._bx;

const m = mergeKnowledgeUnits(st.results, st.paragraphRoles);

// Conflicts are OBSERVABILITY ONLY this iteration (no schema change, no review queue).
if (m.conflicts.length) {
  console.log('[SW-008 merge] ' + m.conflicts.length + ' conflict(s) — same statement, differing '
    + 'category/authoritySource. Ranking selected by evidence quality:');
  for (const c of m.conflicts.slice(0, 10)) {
    console.log('  conflict on [' + c.conflictOn.join(',') + '] :: "'
      + c.statement.slice(0, 90) + '" :: ' + JSON.stringify(c.occurrences));
  }
  if (m.conflicts.length > 10) console.log('  ... and ' + (m.conflicts.length - 10) + ' more');
}

console.log('[SW-008 merge] ' + JSON.stringify({
  batches: st.results.length,
  totalExtracted: m.stats.totalExtracted,
  unique: m.stats.unique,
  duplicatesDropped: m.stats.duplicatesDropped,
  replacedByBetterEvidence: m.stats.replacedByBetterEvidence,
  conflictsDetected: m.stats.conflictsDetected,
  ungroundedRejected: st.rejected.length,
  paragraphsCovered: st.planStats.totalParagraphs,
}));

// ---- EMIT THE EXACT CONTRACT SW-009 ALREADY CONSUMES ----
// { ...incoming, knowledge: { knowledgeUnits: [...] } }
// Batching is INVISIBLE outside this workflow. No downstream change, no schema change.
return [{ json: { ...incoming,
  knowledge: { knowledgeUnits: m.knowledgeUnits },
  _extraction: {                       // observability only; not consumed downstream
    batches: st.results.length,
    stats: m.stats,
    conflicts: m.conflicts,
    ungroundedRejected: st.rejected,
  } }}];
